insert into public.exercises
  (id, name, muscle_group_id, equipment, image_url, instructions, is_warmup, source, source_id, license_author, license_url)
values
  ('step-jack', 'Step Jack', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1962/74041371-1019-4f89-9ebe-cec792484a46.png', 'The Step Jack is a low-impact plyometric-style move that provides cardiovascular benefits without the joint stress of jumping. It works the entire body, specifically targeting the legs, core, and shoulders. This move is ideal for beginners, individuals with joint sensitivities, or as a dynamic warm-up to gradually elevate the heart rate. Notes (Instructions): ​Stand upright with your feet together and arms at your sides. ​Step your right foot out to the side while simultaneously swinging both arms up above your head. Bring your right foot back to the center and lower your arms. ​Immediately repeat the movement, stepping out with your left foot. ​Continue alternating sides at a steady, rhythmic pace.', false, 'wger', '2f10d91f-6c12-471b-bb9e-80840a56ce01', '', ''),
  ('slow-squat', 'Slow Squat', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1963/db285682-1ab3-4be0-ae00-5117ecce1ee6.png', '​A tempo-based squat that uses controlled movement to increase muscle tension and improve lower-body stability. ​Lower: Descend slowly for 3 seconds. ​Pause: Hold at the bottom for 1 second. ​Stand: Return to the starting position at a normal pace. Form: Keep your chest up and weight in your heels.', false, 'wger', '2398e14f-02a6-4fdc-9f69-029e52dfe033', '', ''),
  ('marching-high-knees', 'Marching High Knees', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1965/03c08a42-dedb-4a46-8d15-acaf497a35a2.png', 'A low-impact cardio and mobility exercise that strengthens the hip flexors and improves balance. ​Movement: Stand tall and lift one knee toward your chest as high as comfortable. ​Arms: Swing the opposite arm forward as you lift your knee, similar to a walking motion. ​Core: Keep your abs engaged to maintain an upright posture. ​Pace: Perform the movement with control, alternating legs rhythmically.', false, 'wger', 'fad49a13-b2a0-4b1f-b262-29b32248257d', '', ''),
  ('step-ups', 'Step-ups', 'legs', 'Bench', 'https://wger.de/media/exercise-images/981/f9377a7e-eb58-4cca-b805-2d36863aeb03.png', 'Starting position: Stand facing a chair. Steps: Step up onto the chair. Step off the chair. Repeat.', false, 'wger', '9e6dae29-5d03-440a-bdf1-2cb25a5179c2', '', ''),
  ('single-arm-dumbbell-shoulder-press', 'Single-arm dumbbell shoulder press', 'shoulders', 'Dumbbell', 'https://wger.de/media/exercise-images/1968/cd92e973-a0d9-4e5f-9011-5369012598d3.png', 'Press the dumbbell vertically overhead in a controlled motion until your arm is fully extended, without locking the elbow. Slowly lower the dumbbell back to the starting position at shoulder height.', false, 'wger', '9dfce8f0-39fc-4204-9f84-500ec42074e9', '', ''),
  ('mentzer-pulldown', 'Mentzer Pulldown', 'arms', 'Incline bench', 'https://wger.de/media/exercise-images/1971/729af526-19a0-4d3d-a258-196c7575d139.jpg', 'Close grip front facing Pull down, while focusing on Biceps, Increases activation of biceps over the whole range, Avoid activating Lats.', false, 'wger', 'c4185277-1d30-4684-9bc0-024ab7f2336a', 'Athlean-X', ''),
  ('single-arm-plank-to-row', 'Single Arm Plank to Row', 'back', 'Kettlebell', 'https://wger.de/media/exercise-images/1022/f74644fa-f43e-46bd-8603-6e3a2ee8ee2d.jpg', 'Start position as row, extend to plank and back. Finish with row and repeat', false, 'wger', '768e0703-a04d-4d97-89ce-a49cd6be2b06', '', ''),
  ('curl-de-mu-eca-con-barra', 'Curl De Muñeca Con Barra', 'arms', 'Barbell, Bench', 'https://wger.de/media/exercise-images/2452/f6262118-1e01-4a98-b8aa-1cc69d383311.png', 'This is a variation of the flat bench press designed to emphasize the clavicular head of the pectoralis major (the upper portion). By tilting the torso, the angle of the push changes, shifting more tension to the upper chest and shoulders, which helps achieve a more aesthetic, balanced, and three-dimensional development of the torso. Starting Position: Grip a bar with an overhand grip (palms facing up) at a width similar to your shoulders. Position on the Bench: Kneel in front of a flat bench and rest the backs of your forearms on it. Your wrists and hands should extend slightly beyond the edge of the bench to allow for a full range of motion. Eccentric Phase (Lowering): Lower the bar in a controlled manner by extending your wrists toward the floor. At the bottom of the movement, slightly spread your fingers to let the bar roll down a bit, maximizing the stretch. Concentric Phase (Lift): First, close your fingers to secure the bar, then flex your wrists upward explosively but in a controlled manner, bringing the bar as high as possible. Strongly contract your forearms at the top position for one second. Form: Keep your forearms firmly pressed against the bench throughout the exercise; only your wrists and fingers should move.', false, 'wger', '4b67ccf1-6bbc-406a-b88b-e2f72b10085e', '', ''),
  ('suspended-crossess', 'Suspended crossess', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/927/7b392101-9c47-4693-935e-a88b1887eec5.jpg', 'Suspension exercise with trx for chest training', false, 'wger', 'e0d9e9ef-09ee-4d26-9504-622093810414', '', ''),
  ('high-knees', 'High knees', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/983/16245344-9957-4a24-8d61-f9939ed5f964.png', 'Starting positionStand straight. Steps: Run in place, putting knees as high up as is comfortable and switching legs at a quick pace.', false, 'wger', 'db5bd076-2f1d-4b72-9be9-610e5c3f5724', '', ''),
  ('kneeling-kickbacks', 'Kneeling kickbacks', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/990/de20457c-914a-45c9-8cf9-0ad9739759a1.png', 'Starting position: Get down on all fours. Steps: Push one foot back until fully extended, concentrating on the gluteus muscles. Stay for one second, then return to the initial position. Repeat, alternating feet.', false, 'wger', '6ddea666-5a57-4ac0-926f-01f8cfdaa4fd', '', ''),
  ('axe-hold', 'Axe Hold', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/31/92f6451b-f89d-49d6-9531-8970ea420d97.png', 'Grab dumbbells and extend arms to side and hold as long as you can', false, 'wger', 'f2733700-aa5d-4df7-bc52-1876ab4fb479', '', ''),
  ('tricep-pushdown-on-cable', 'Tricep Pushdown on Cable', 'arms', null, 'https://wger.de/media/exercise-images/805/7a437824-e2cc-46e1-804a-674f0ea31d25.png', 'The cable rope push-down is a popular exercise targeting the triceps muscles. It''s easy to learn and perform, making it a favorite for everyone from beginners to advanced lifters. It is usually performed for moderate to high reps, such as 8-12 reps or more per set, as part of an upper-body or arm-focused workout.', false, 'wger', 'ea63d85c-8579-4dda-b99f-c4c8930f9af6', '', ''),
  ('incline-bench-reverse-fly', 'Incline Bench Reverse Fly', 'back', 'Dumbbell', 'https://wger.de/media/exercise-images/828/2e959dab-f39b-4c7c-9063-eb43064ab5eb.png', 'The incline dumbbell reverse fly is an upper-body exercise targeting the posterior or rear deltoids, as well as the postural muscles of the upper back. Because it targets such small muscles, this exercise is usually performed with light weight for high reps, such as 10-15 reps per set or more.', false, 'wger', '70c99a4e-3340-4993-a7f1-2d2709dada1a', 'cshep442', ''),
  ('biceps-with-trx', 'Biceps with TRX', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/958/947ac249-475d-44ed-bed3-8dc433374f59.png', 'Grab the handles of the TRX straps, lean your body back, arms and legs extended, with your body positioned in a single straight line. (This is an arm exercise, not an abdominal one.)', false, 'wger', '596b9d2d-0f01-41a0-97e1-1839ffdb824d', 'cynomops', ''),
  ('kettlebell-swing', 'Kettlebell Swing', 'shoulders', 'Kettlebell', 'https://wger.de/media/exercise-images/960/da4d0560-da89-4bb5-b91f-746458fb04ad.png', 'While kettlebell swings are a full-body workout, they mostly target the muscles along the posterior chain (back of the body). The main muscles used are the glutes, hamstrings, spinal erectors, and muscles of the upper back.', false, 'wger', 'd813ef7c-b10a-4c5c-ba55-6b9518e7ff4c', '', ''),
  ('one-handed-kettlebell-curls', 'one-handed kettlebell curls', 'arms', 'Kettlebell', 'https://wger.de/media/exercise-images/975/41d9267a-99bc-4e94-b1c4-0e39fe7a968f.png', 'Standing with the kettlebell in one hand and bent at the elbow, start from a fully extended position until your hand reaches shoulder height. To perform the movement correctly, try not to push with your back or body.', false, 'wger', 'd7d4fc16-08cd-4568-87e7-d9e4e2f77393', '', ''),
  ('medicine-ball-booklet-crunch', 'Medicine ball booklet crunch', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/976/94649ea6-bf58-4fd9-90c1-b2ec96ee20cd.png', 'Using a medicine ball as an overload will make the exercise heavier.', false, 'wger', '346634cf-3896-4c10-bd66-28fb69d02573', '', ''),
  ('box-squat', 'Box squat', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/977/3124c091-6395-4377-96c5-56048b627ceb.png', 'Set up the box: Position the box behind you, about 3 feet from a squat rack if you''re using a barbell. Choose a height that allows you to squat down and gently tap your glutes on the box with your back straight. Stand with proper form: Stand with your feet shoulder-width apart, toes pointed slightly outward. Engage your core and keep your back neutral. If using a barbell, rack it at shoulder height. Lower down: Sit back as if going to sit on a chair, bending your knees and lowering your hips towards the box. Keep your core tight and back straight throughout the movement. Controlled descent: Descend in a controlled manner until your glutes gently touch the box. Don''t plop down. Pause and press up: Briefly pause at the bottom with your back straight and core engaged. Then, press through your heels to drive yourself back up to the starting position. Improvements in coordination, balance and endurance, toning of the leg and buttock muscles and an overall increase in bone density eliminating the risk of osteoporosis.', false, 'wger', '151434a5-c046-459f-a3a9-c3125075856f', '', ''),
  ('knee-raises', 'Knee Raises', 'core', 'Pull-up bar', 'https://wger.de/media/exercise-images/978/d3ffe51f-7eb8-4cc9-9eae-105847af3005.png', 'The 90° leg raise on the bar is a very intense exercise that involves all the abdominal muscles.', false, 'wger', 'f4991a98-6422-4884-8ad3-43412f91fac1', '', ''),
  ('sloper-hanging', 'Sloper hanging', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/804/6f4b8bd9-fa05-49de-870b-1f79b595ce89.png', 'Hanging on sloper holds of a fingerboard for a amount of seconds', false, 'wger', '9f9edad8-7da0-448c-bfcb-ec61f2d28162', '', ''),
  ('barbell-ab-rollout', 'Barbell Ab Rollout', 'core', 'Barbell', 'https://wger.de/media/exercise-images/41/34b37423-269f-43d4-9d29-d2a90eeaa6b4.png', 'Place a barbell on the floor at your feet. Bending at the waist, grip the barbell with a shoulder with overhand grip. With a slow controlled motion, roll the bar out so that your back is straight. Roll back up raising your hips and butt as you return to the starting position.', false, 'wger', 'a6bced3c-72f5-42a3-9438-5569d46f49fd', '', ''),
  ('reverse-nordic-curl', 'Reverse Nordic Curl', 'legs', null, 'https://wger.de/media/exercise-images/909/159222d9-c1e4-46ae-89ee-6a2dfaab978d.png', 'Natural Leg Extension is alternative to Leg Extension machine with no equipment.', false, 'wger', '6cbdd70c-0691-4288-b58a-24001384f1b3', '', ''),
  ('straight-bar-cable-curls', 'Straight Bar Cable Curls', 'arms', null, 'https://wger.de/media/exercise-images/912/e10a034f-6370-4dd6-b1c2-416b27844529.png', 'Standing upright in front of Cable Tower using a straight bar', false, 'wger', '36274d27-3812-4b8c-80e2-ab59acf82c4d', '', ''),
  ('trx-rows', 'TRX Rows', 'back', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/959/53a5e008-bc31-4ee0-9463-69a858c2ec18.png', 'This exercise serves as a lead-up to Pull Ups.', false, 'wger', 'e2599e86-d8b0-434e-8a48-aa3c2df7e790', 'clafal', ''),
  ('leg-raises-pull-up-bar', 'Leg raises pull up bar', 'core', 'Pull-up bar', 'https://wger.de/media/exercise-images/979/27097a3a-5749-428d-b94c-6082afe390f6.png', 'with a firm grip with both hands on the bar, raise your outstretched legs, until you reach a 90° angle with your torso.', false, 'wger', 'b2025776-2397-4de7-a49e-296321169481', '', ''),
  ('bent-high-pulls', 'Bent High Pulls', 'shoulders', 'Dumbbell', 'https://wger.de/media/exercise-images/79/da58dfbf-748a-461b-891e-3d6bc9cc4be2.png', 'Bend over slightly while holding two dumbbells.&nbsp; Pull the dumbbells up to your chest, keeping your elbows as high as you can.', false, 'wger', '01271ea0-088c-4e2b-95ad-876af7127057', '', ''),
  ('floor-dips', 'Floor dips', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1000/553266a8-a972-48c5-a014-b12afac66f65.png', 'Starting position: Sit with your arms behind you, supporting your back.Your fingers should point forward.Your knees should be bent, feet together. Steps: Raise your hips off the ground, straightening your arms. Bend your elbows, bringing your hips down. Straighten your arms, returning to the previous position. Repeat steps 2 and 3. Notes: The exercise''s difficulty depends on how high you bring your hips.', false, 'wger', 'cf79d9fb-ffce-4648-a64f-27e4274e4c20', 'Franpol', ''),
  ('child-s-pose', 'Child''s pose', 'back', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1002/ddf91765-8045-4087-bece-de17f33332ce.png', 'Starting position: Start on all fours, knees, toes, and hands touching the ground. Your two big toes should be touching. Steps: Move your knees so that they''re about hip-width apart. On an exhale, move your pelvis back to sit on your heels. Your hands should still be touching the ground. Relax your upper body, lowering your forehead to the floor and letting your hands move forward naturally. Stay in this pose. Tips: To leave the pose, walk your arms back under your shoulders and move your upper body up into a seated position.', false, 'wger', '6e1af72c-f9f5-490d-8977-564df4f24b6f', '', ''),
  ('kettlebell-deadlifts', 'Kettlebell deadlifts', 'back', 'Kettlebell', 'https://wger.de/media/exercise-images/1003/772d6e47-3865-4944-9255-7435d0b06782.png', 'Starting position: Stand hip-width apart, with your kettlebell centered between your ankles. Your back should be straight, your head facing forward. Steps: Hinge at the hips and slightly bend at the knees to put your hands on the kettlebell handles. Your back should be straight as you perform the movement. Grab the kettlebell handles, with your hands pushing in opposite directions as if to pull the handle apart. While contacting your abs and glutes, stand straight up. Hinge at the hips again to bring the kettlebell back down, similarly to step 1. Repeat from step 3. Tips: Be sure you''re performing the movements correctly, as doing otherwise can lead to injury. For example, do not squat instead of hinging at the hips, do not round your back while reaching for the kettlebell, and do not lean back while standing up.', false, 'wger', '9b5f8c6e-2436-4ded-aea9-8c698b0c8768', '', ''),
  ('head-turns', 'Head turns', 'shoulders', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1007/757846d3-78e4-4068-bbca-62e567372c94.png', 'Starting position: Sit or stand with your back straight and shoulders down. Steps: Sit or stand up straight, shoulders dropped. Turn your head to the side as far as possible. Stop when you hit a barrier and hold for 5 seconds. Return to center position and repeat, changing sides.', false, 'wger', '336e224a-a7a1-4808-9871-1ad8cfc3fee7', '', ''),
  ('alternating-bicep-curls', 'Alternating bicep curls', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1012/8270fdb8-28f1-4eff-b410-af8642085b3f.png', 'Starting position: Start standing up with dumbbells in each hand, your back straight and feet hip-width apart. Your arms should be relaxed, pointing down. Your knees should be slightly bent, your abs contracted, and your shoulders down. Steps: Bend one arm at the elbow, bringing the dumbbell up to your shoulder. Your upper arm should remain motionless during this movement. Bring the dumbbell back down until your arm is in its original relaxed position. Repeat, switching arms.', false, 'wger', 'a136959c-b0c8-49d3-99b9-0a5f41abf00e', 'Franpol', ''),
  ('head-tilts', 'Head tilts', 'back', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1018/5bbd3879-b6fc-4aaa-9e8e-33ae9a688112.png', 'Starting position: Sit or stand with your back straight. Steps: Tilt your head to one side and hold for a bit.2.Return your head to neutral position and hold for a bit. Tilt your head to the other side and hold for a bit. Return your head to neutral position yet again and hold for a bit. Repeat.', false, 'wger', '36eaf240-db34-4d83-bba9-94d0e989c9e2', '', ''),
  ('lunges', 'Lunges', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/984/5c7ffe68-e7b2-47f3-a22a-f9cc28640432.png', 'Starting position: Stand with back straight. Steps: Take a large step forward with your left leg. Bring your pelvis down until you almost touch the floor with your right knee. Bring your pelvis back up. Return to the starting position by stepping back. Repeat, switching legs each time.', false, 'wger', '3284fd27-5402-4821-9c32-29066d4e2667', 'Franpol', ''),
  ('bulgarian-split-squats-left', 'Bulgarian split squats left', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/988/6283b258-a4d7-4833-84f7-a38987022d3d.png', 'Stand tall in front of a chair and take a large step. Put the upper part of one of your feet on the chair. Bend the front knee, balancing with arms until the back knee almost touches the ground. Push back to the starting position and repeat.', false, 'wger', '7ce489d2-1948-46de-aa80-277b2ca737aa', 'Franpol', ''),
  ('reverse-lunges', 'Reverse lunges', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/999/d0931eb3-8db0-4049-bb08-aa4036072056.jfif', 'Starting position: Stand straight, feet hip-width apart. Steps: Step backward with one leg so it can bend comfortably to a 90 degree angle. Slowly bend both knees to form 90 degree angles. Return to the starting position. Repeat, alternating legs.', false, 'wger', '616f9026-1a1d-4ed8-b068-cfbb81b6a000', 'philip', ''),
  ('smith-machine-slight-incline-press', 'Smith Machine Slight Incline Press', 'chest', null, 'https://wger.de/media/exercise-images/925/67dbb1c9-b378-46f9-adb6-1f55b3d3007a.png', '* Execution * Start position: Unrack the bar and hold it above your upper chest with arms fully extended. Keep your shoulder blades&nbsp;retracted and pressed into the bench. Lowering phase (eccentric): Slowly bring the bar down to just below your collarbone or upper chest. Maintain control — don’t bounce the bar. Pressing phase (concentric): Push the bar upward in a straight line until your arms are fully extended. Focus on&nbsp;squeezing your upper chest&nbsp;at the top. Lock and repeat: Complete your reps, then safely rack the bar back into the hooks.', false, 'wger', 'ef2df6a2-41df-4a25-b2e0-4808dc2c3305', '', ''),
  ('chest-press', 'Chest Press', 'chest', null, 'https://wger.de/media/exercise-images/129/b263c968-e067-4750-916a-d8758a7df23e.webp', 'Adjust the seat height so that the grips are parallel to your chest. Use your legs to push the foot forward pedal. Bring the handles to the start position. Keep your back in contact with the back pad, press outwards. Press the handles away from your chest and exhale. Allow the handles to come in gently until they reach your chest. Allow the handles to return to your chest as you inhale.', false, 'wger', '5c414175-fe72-455a-ba8f-a0575cf792bd', 'roneydya', ''),
  ('cross-bench-dumbbell-pullovers', 'Cross-Bench Dumbbell Pullovers', 'chest', 'Dumbbell', 'https://wger.de/media/exercise-images/161/b9b1803e-2817-40bf-8ac7-e398ca86d8b4.png', 'Grasp a moderately weighted dumbbell so your palms are flat against the underside of the top plates and your thumbs are around the bar. Lie on your back across a flat bench so only your upper back and shoulders are in contact with the bench. Your feet should be set about shoulder-width apart and your head should hang slightly downward. With the dumbbell supported at arm''s length directly about your chest, bend your arms about 15 degrees and keep them bent throughout the movement. Slowly lower the dumbbell backward and downward in a semicircle arc to as low a position as is comfortably possible. Raise it slowly back along the same arc to the starting point, and repeat for the required number of repetitions.', false, 'wger', '6e00afb6-272d-44a2-8ae3-e7fa41b50f06', '', ''),
  ('chin-up', 'Chin Up', 'back', 'Pull-up bar', 'https://wger.de/media/exercise-images/152/6c1a7459-266d-491a-bd50-7cbaea2bc771.png', 'The chin-up (also known as a chin or chinup) is a strength training exercise. People frequently do this exercise with the intention of strengthening muscles such as the latissimus dorsi and biceps, which extend the shoulder and flex the elbow, respectively. In this maneuver, the palms are faced towards the body. It is a form of pull-up in which the range of motion is established in relation to a person''s chin.', false, 'wger', '87e6abc5-a701-442a-b4fb-bb2a7598a754', 'Everkinetic', ''),
  ('machine-chest-fly', 'Machine chest fly', 'chest', null, 'https://wger.de/media/exercise-images/926/ae9deb5d-a1e9-4c30-b1e3-c128ba5d4969.png', 'seated machine, straight back, slow exercise', false, 'wger', '1e827ef8-0a01-4b26-9e26-eff9d200acca', '', ''),
  ('hyperextensions', 'Hyperextensions', 'back', null, 'https://wger.de/media/exercise-images/128/Hyperextensions-1.png', 'Lie on the hyperextension pillow with your navel at the front edge, allowing your upper body to hang freely. Tighten all your back muscles and raise your torso until you''re horizontal, but no higher. Lower yourself slowly, maintaining a steady flow of muscles.', false, 'wger', '37f6bd56-815a-4975-99af-05e749fae4b2', 'Everkinetic', ''),
  ('high-knee-jumps', 'High Knee Jumps', 'legs', null, 'https://wger.de/media/exercise-images/285/4141e8b2-d9f2-4597-8ef0-7768127fd0ec.png', 'Start with legs slightly wider than shoulder width Drop into a bodyweight squat As you hit the bottom of the squat, explode upwards into a jump while simultaneously tucking your knees into your chest midflight.&nbsp; Remain tucked until the apex of your jump. Land on both feet, making sure your knees are not locked so as to avoid excessive strain upon your joints.&nbsp; Collect yourself into the next rep as quickly but under control as possible.', false, 'wger', '3edbb63e-f326-4bd0-8af3-2d5deabb864f', '', ''),
  ('bus-drivers', 'Bus Drivers', 'shoulders', null, 'https://wger.de/media/exercise-images/915/fe8ebece-dff8-4700-b84c-9110e2e074f5.png', 'Sitting with a Weight Plate, used as wheel, in both hands; raised slightly below eye level', false, 'wger', '3d85bdce-e1a9-48a2-b14d-8032820ebf25', '', ''),
  ('hand-grip', 'Hand Grip', 'arms', null, 'https://wger.de/media/exercise-images/279/36605bc8-d7e1-43e1-87c1-b9cb50db62b2.webp', 'chrome Hand Flex Grip to build up forearms muscles', false, 'wger', '4e238360-a4c1-4509-85c1-f96d01e69cf9', '', ''),
  ('hollow-hold', 'Hollow Hold', 'core', 'Gym mat, none (bodyweight exercise)', 'https://wger.de/media/exercise-images/297/b10d3341-baa8-49ab-b462-5b3529389aac.png', 'Get on a mat and lie on your back. Contract your abs, stretch your arms and legs and raise them (your head and shoulders are also be raised). Make sure your lower back remains in contact with the mat.', false, 'wger', 'd059c63d-0a81-48a3-912a-44070c0def2e', '', ''),
  ('rope-pullover-row', 'Rope Pullover/row', 'back', 'Incline bench', 'https://wger.de/media/exercise-images/1634/9a4704d3-1b25-43e3-b244-3885f4d3db87.png', 'Set up bench in front of cable row machine. Lean over bench to do a row/pullover with rope that targets lats. See picture.', false, 'wger', '148f2ffc-05e2-486b-874f-2a401337a1c6', 'Rottekongen', ''),
  ('single-arm-row', 'Single arm row', 'back', 'Incline bench', 'https://wger.de/media/exercise-images/1637/a1fbe83a-a3e5-49f6-a2c2-5d5b533c2be8.png', 'Sitting on the ground, use a high cable in a single grip, to do lat pulldowns with a focus on a long stretch in the lats.', false, 'wger', '81dd44b3-67b3-4198-9e57-c2a80b3c4102', 'Rottekongen', ''),
  ('barbell-clean-and-press', 'Barbell Clean and press', 'chest', 'Dumbbell', 'https://wger.de/media/exercise-images/1638/046c09b0-c35d-48d0-a552-39dd49f956d2.webp', 'This exercise involves lifting a barbell from the ground to the shoulders, then pressing it overhead. It is a compound movement that targets multiple muscle groups, including the legs, back, shoulders, and arms. It is often used in strength and conditioning programs to improve overall power and athleticism.', false, 'wger', 'e9e7372c-b5c1-45d9-ae5c-b1aa0fc2e2ce', 'Rottekongen', ''),
  ('smith-press', 'Smith Press', 'shoulders', 'Incline bench', 'https://wger.de/media/exercise-images/916/9bf7555a-fec6-43a9-b343-aae496744e5e.png', 'Sitting almost 90 degree angle, smith machine', false, 'wger', 'cbf4cf16-f188-4a60-a223-aa50b163f4b7', '', ''),
  ('jumping-jacks', 'Jumping Jacks', 'legs', null, 'https://wger.de/media/exercise-images/320/6c9124b6-3551-47a8-9c22-20141c8b9c53.png', 'A jumping jack or star jump, also called side-straddle hop in the US military, is a physical jumping exercise performed by jumping to a position with the legs spread wide and the hands going overhead, sometimes in a clap, and then returning to a position with the feet together and the arms at the sides', false, 'wger', '4d255f25-f199-401a-bc81-7ffab1d0ed24', '', ''),
  ('cable-cross-over', 'Cable Cross-over', 'chest', null, 'https://wger.de/media/exercise-images/71/Cable-crossover-2.png', 'Begin with cables at about shoulder height, one in each hand. Take a step forward so that one foot is in front of the other, for stability, and so that there is tension on the cables. Bring hands together in front of you. Try to make your hands overlap (so that the cables cross) a few inches.', false, 'wger', 'b16e3e5d-8401-4d2b-919c-15b536f9ec5e', 'Everkinetic', ''),
  ('quadriped-arm-and-leg-raise', 'Quadriped Arm and Leg Raise', 'back', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/957/0fd94587-6021-4763-856e-7227f5fcba2a.png', 'In this exercise, the back muscles and the muscles of the back of the leg and back of the arm are activated by lifting the crossed arm and leg at the same time in the crawling position. It also improves balance and proprioception. The movement is done symmetrically. Get into a crawling posture.2. Draw your abdomen in, then raise your right leg and left arm.3. You should keep your abdomen in for 8 seconds.4. After 8 seconds, slowly lower your arm and leg.5. Then release your muscle.', false, 'wger', '80c167b9-3749-48a1-8686-fc2163a1e7fb', 'utkb', ''),
  ('long-pulley-low-row', 'Long-Pulley (low Row)', 'back', null, 'https://wger.de/media/exercise-images/143/Cable-seated-rows-2.png', 'Sit down, put your feet on the supporting points and grab the bar with a wide grip. Pull the weight with a rapid movement towards your belly button, not upper. Keep your arms and elbows during the movement close to your body. Your shoulders are pulled together. Let the weight slowly down till your arms are completely stretched.', false, 'wger', 'a7e6c20a-6ddc-4401-9935-ace2d02e3995', 'Everkinetic', ''),
  ('pike-push-ups', 'Pike Push Ups', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/454/447f3c17-405f-46e0-b138-65c2a8caaab0.png', 'Push Up performed from a pike position (optional to have feet elevated).', false, 'wger', '3b96a05b-9705-48da-b43e-6e098234bb35', '', ''),
  ('modified-pulldown', 'Modified pulldown', 'back', 'Incline bench', 'https://wger.de/media/exercise-images/1635/b8c34e3a-7474-41ea-99e3-8d7fdb1e12d6.png', 'With an inclined bench in front of the pulldown machine, use a close-grip to do latfocused pulldowns.', false, 'wger', '5851e2b1-3a80-42ff-91da-530e6b143a34', 'Rottekongen', ''),
  ('dumbbell-bent-over-face-pull', 'Dumbbell Bent Over Face Pull', 'back', 'Dumbbell', 'https://wger.de/media/exercise-images/1639/8927346e-f5ca-4795-bdf1-5ac9309401e7.webp', 'This exercise involves using dumbbells to perform a bent over face pull, which targets the upper back and shoulders. The movement involves pulling the weights towards the face while keeping the elbows high and squeezing the shoulder blades together.', false, 'wger', '51ab6376-eb3e-42dc-ad48-46166c94adac', 'AlucardEvil40', 'https://liftmanual.com/dumbbell-bent-over-face-pull/'),
  ('incline-bench-press-mp', 'Incline Bench Press - MP', 'chest', null, 'https://wger.de/media/exercise-images/61/Close-grip-bench-press-1.png', 'Move slowly, keep control, and stop if anything feels painful.', false, 'wger', '60e9a0c0-5458-46cd-ab41-7d7b85225cf8', 'Everkinetic', ''),
  ('hindu-pushups', 'Hindu Pushups', 'chest', null, 'https://wger.de/media/exercise-images/1080/c4bf7ba1-6058-4d14-928f-7187885d5d57.webp', 'Exercise to strengthen the shoulders and pectorals. Its name is due to the fact that it begins in the Yoga position "Dog Facing Down", passing to "Cobra" but without resting the legs or torso on the ground to finally end with a normal flexion. The exercise can also be performed backwards (back to the starting position). As a variation, after doing the push-up, the hip can be raised to return to downward facing dog.', false, 'wger', '476c1d96-6590-4f86-98f0-3f12808fab53', 'Imobard', ''),
  ('close-grip-press-ups', 'Close-grip Press-ups', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1086/b2ee8d9b-0480-4992-8494-c223b37c2696.jpg', 'Drop into a strong plank position, bringing your hands close together until they''re almost touching.&nbsp;(picture 1)Bend your elbows to slowly bring your chest to the floor&nbsp;(picture 2). Keep your elbows close to your body as you push back up explosively. Repeat. Ensure you take your time lowering on each rep, keeping your form sharp.', false, 'wger', '44cfa56c-d8c2-4f2c-8b5a-f29810fd60e7', 'philip', ''),
  ('dumbbell-hang-power-cleans', 'Dumbbell Hang Power Cleans', 'back', 'Dumbbell', 'https://wger.de/media/exercise-images/1087/d85f4e02-b20c-457c-bdfb-0b00e2d14150.jpg', 'On your feet, stand tall with your dumbbells, holding them at your sides. Hinge at the hips to lower them to your knees (picture 1). Stand back up with a slight jump, using the momentum to pull the dumbbells up on to your shoulders (picture 2). Stand up straight, then lower under control to your sides and repeat. Keep this fast and explosive; if your heart rate doesn’t hit the roof, you’re doing them wrong.', false, 'wger', 'f0f53b8e-0136-4195-baf3-781903651359', 'philip', ''),
  ('dumbbell-sumo-deadlift', 'Dumbbell sumo deadlift', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1088/9f66b288-ce8f-4154-ba80-78fee267263c.jpg', 'Lower your dumbbell to the ground between your legs. Assume a wide stance and with a straight back squat down. With the dumbbell standing upright, grip it by the top of the ‘head’&nbsp;(picture 1).Keeping your chest up and core braced, push the floor away, driving back upwards to a standing position&nbsp;(picture 2). Repeat. If you can easily achieve 20-30 reps, use two dumbbells.', false, 'wger', '0c30c543-e2cc-499b-bc31-8c28db445ed2', 'philip', ''),
  ('medicine-ball-twist', 'Medicine ball twist', 'core', 'Swiss Ball', 'https://wger.de/media/exercise-images/1089/49f51716-535d-41dd-aeb5-cff5bb906bc1.jpeg', 'In a seated position, the torso is rotated from side to side without forcing, approaching the knees and making the ball touch the ground from time to time', false, 'wger', '66c7eb38-77b5-4d2f-810f-cddd8d97d5a3', 'clafal', ''),
  ('plank-shoulder-taps', 'Plank Shoulder Taps', 'shoulders', 'Gym mat', 'https://wger.de/media/exercise-images/1091/50c8912d-54ef-46c9-99d1-633b6196aa1e.jpg', 'In the correct plank position, place your feet slightly wider than shoulder-width apart. alternately lift and touch the opposite shoulder with one hand.', false, 'wger', '75d730d0-3b26-4a25-8f1a-7119a98e02ef', 'clafal', ''),
  ('dumbbell-front-squat', 'Dumbbell Front Squat', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1640/bdea82f1-15ef-4649-8b5a-1303cfc178e7.webp', 'This exercise involves holding a dumbbell in each hand at shoulder height and performing a squat. It targets the lower body muscles, including the quads, hamstrings, and glutes, while also engaging the core and upper body.', false, 'wger', '4621b41f-0d32-4033-acff-dc079c792606', 'AlucardEvil40', ''),
  ('kettlebell-one-legged-deadlift', 'Kettlebell One Legged Deadlift', 'legs', 'Dumbbell, Kettlebell', 'https://wger.de/media/exercise-images/1641/68d9488d-2596-420f-be0f-52aa70732c83.webp', 'This exercise involves holding a kettlebell in one hand and standing on one leg while bending forward to touch the kettlebell to the ground. It targets the hamstrings, glutes, and lower back while also improving balance and stability.', false, 'wger', '20b17b71-6d91-4b56-978a-04b7f94c04cc', 'AlucardEvil40', ''),
  ('dumbbell-hip-thrust', 'Dumbbell Hip Thrust', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1642/a81ad922-caf5-47f8-99b4-640cb0717436.webp', 'This exercise involves sitting on the ground with a dumbbell resting on the hips, then thrusting the hips upward while squeezing the glutes. It is a great exercise for strengthening the glutes and improving hip mobility.', false, 'wger', 'af77220c-098c-47c2-9f8c-92a651998903', 'AlucardEvil40', ''),
  ('weighted-crunch', 'Weighted Crunch', 'core', 'Dumbbell', 'https://wger.de/media/exercise-images/1648/63ae02d6-6dd9-4e9e-84da-d4905e78a33c.jpg', 'The Weighted Crunch is a variation of the classic crunch exercise that involves adding resistance (a weight) to increase the intensity of the abdominal work. Lay down (Optional) Bend your knees to add difficulty (Optional) Bend your knees and let your feet rest on a bench or a box or something (90 degree angle on knees) Lift your head and torso while bending your back forward (if you don''t it''s a sit-up and also involves some back muscles). The higher you go, the more you should feel your abs contracting. Go back to starting position an repeat', false, 'wger', '8d333b94-148c-48f8-9154-8b13279500d1', 'AlucardEvil40', ''),
  ('dumbbell-side-bend', 'Dumbbell Side Bend', 'core', 'Dumbbell', 'https://wger.de/media/exercise-images/1650/1d7a5336-ec0b-4898-a474-78ba32789bf3.webp', 'This exercise involves holding a dumbbell in one hand and bending sideways to work the oblique muscles on the side of the body. It can be done standing or seated and is often used as a core strengthening exercise.', false, 'wger', '3e9b3bb0-7958-4836-89a5-ed0c5f7eeb03', 'AlucardEvil40', ''),
  ('dumbbell-rear-lunge', 'Dumbbell Rear Lunge', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1651/04ab2679-a04d-4d05-9c85-0d36e898328c.webp', 'This exercise involves holding a dumbbell in each hand and stepping back into a lunge position, then returning to standing. It primarily targets the glutes, hamstrings, and quadriceps.', false, 'wger', '75e34967-b0ec-40d5-811e-b474b234a7a9', 'AlucardEvil40', ''),
  ('dumbbell-side-squat', 'Dumbbell Side Squat', 'legs', null, 'https://wger.de/media/exercise-images/1653/c10c4e17-1e14-4cf9-930b-cc3a614f15dd.webp', 'This exercise involves holding a dumbbell in one hand and performing a squat while stepping to the side. It targets the legs, glutes, and core muscles.', false, 'wger', '412ba9ab-ae29-4411-9bbc-74af1263494c', 'AlucardEvil40', ''),
  ('machine-lateral-raise', 'Machine Lateral Raise', 'shoulders', 'Gym mat', 'https://wger.de/media/exercise-images/1654/aa724a58-b3b5-4522-b278-1155416236a5.jpg', 'The machine lateral raise is an isolation exercise that targets the medial (side) deltoid muscle to build wider, more defined shoulders. The machine''s fixed path of motion provides greater stability than dumbbells, making it ideal for beginners or those who want to focus solely on muscle activation.', false, 'wger', '3d2adf99-8fe9-45cb-b669-c5b18242e282', 'roneydya', 'https://fitnessvolt.com/wp-content/uploads/2022/11/Machine-Lateral-Raise-Exercise-Target-Muscle-750x500.jpg'),
  ('dumbbell-romanian-deadlift', 'Dumbbell Romanian Deadlift', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1652/0306c8c0-70cc-45d4-92de-6fa72ceaa834.webp', 'This exercise involves holding a dumbbell in each hand and bending forward at the hips while keeping the back straight, then returning to a standing position. It primarily targets the hamstrings and glutes.', false, 'wger', '65d12ecf-54b8-466d-a412-e55c396cad69', 'AlucardEvil40', ''),
  ('bent-over-rowing-reverse', 'Bent Over Rowing Reverse', 'back', 'Barbell', 'https://wger.de/media/exercise-images/110/Reverse-grip-bent-over-rows-1.png', 'The same as regular rowing, but holding a reversed grip (your palms pointing forwards): Grab the barbell with a wide grIp (slightly more than shoulder wide) and lean forward. Your upper body is not quite parallel to the floor, but forms a slight angle. The chest''s out during the whole exercise. Pull now the barbell with a fast movement towards your belly button, not further up. Go slowly down to the initial position. Don''t swing with your body and keep your arms next to your body.', false, 'wger', '2f0ddf9a-f520-4c55-8883-f0d4a789f481', 'Everkinetic', ''),
  ('seated-rear-delt-rise', 'Seated rear delt rise', 'back', 'Dumbbell', 'https://wger.de/media/exercise-images/1098/fa5328a2-64cb-4afb-a283-b3d948ddaf3f.jpg', 'Seated, bent 45 deg forward. Arms fully stretched out, raise arms up to shoulder height and back down', false, 'wger', 'c302fd80-ce74-4202-9eee-30834872cffb', 'philip', ''),
  ('wall-balls', 'Wall balls', 'shoulders', 'Swiss Ball', 'https://wger.de/media/exercise-images/1100/ab203e0c-8220-4537-987c-871eb259d687.jpg', 'Get a medicine ball, shoulder width stance, squat, thrust the ball as high as possible against the wall and catch', false, 'wger', 'f20ab712-f953-4705-8710-9681392ddd07', 'philip', ''),
  ('seated-knee-tuck', 'Seated Knee Tuck', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1105/36776818-799a-40bf-9eca-aebb3aa5008f.png', 'Sit on floor or mat. Place arms slightly behind you. Raise legs. Now extend your legs and pull them back.', false, 'wger', '371cfda2-1de6-419a-b40c-fc98fd3f7e41', 'utkb', ''),
  ('cable-concentration-curl', 'Cable Concentration Curl', 'arms', null, 'https://wger.de/media/exercise-images/1109/00b0a0bf-c14a-4f13-bb14-62c09030a1aa.png', 'The concentration curl is a classic exercise for building the biceps one arm at a time. It can be performed bent over or kneeling, but is more often performed seated on a bench. It''s great for emphasizing the biceps peak and is often used to finish a biceps workout', false, 'wger', 'b1bf02cf-17b2-4bfc-a5b0-4ff7a2768dbb', 'Franpol', ''),
  ('push-ups-decline', 'Push-Ups | Decline', 'chest', 'Bench, Incline bench', 'https://wger.de/media/exercise-images/1112/81f40bee-4adf-4317-8476-1a87706e3031.png', 'Decline push-ups are another modified version of the traditional push-up that target the upper body muscles in a different way. To perform a decline push-up, elevate your feet on an elevated surface, such as a bench, chair, or step, while placing your hands on the ground in a push-up position. Lower your body towards the ground while maintaining a straight line from your shoulders to your ankles, and then push back up to the starting position. Unlike the inclined push-up, the decline push-up places more emphasis on the shoulders and triceps, while still engaging the chest muscles to a lesser extent. By elevating your feet, you increase the difficulty of the exercise by placing more weight on your upper body, forcing your shoulders and triceps to work harder to push your body back up. The decline push-up can be a great way to challenge your upper body strength and improve your ability to perform other push-up variations. As with any exercise, be sure to use proper form and start with a height that is appropriate for your strength and fitness level.', false, 'wger', '50037aaf-34f1-4018-b504-206623b77c46', 'anon1337', ''),
  ('remo-maquina-agarre-estrecho', 'Remo maquina agarre estrecho', 'back', null, 'https://wger.de/media/exercise-images/1119/9b138ad2-5b80-42a8-bfff-93a960444ffe.png', 'Remo en máquina con barra en agarre estrecho', false, 'wger', 'ace5d444-6a41-44bc-a4b6-548bb18cfc9b', 'Franpol', ''),
  ('remo-maquina-agarre-estrecho-supino', 'Remo maquina agarre estrecho supino', 'back', null, 'https://wger.de/media/exercise-images/1120/df9a5256-e977-44d0-bc9c-b53253faeb22.png', 'Remo en máquina o polea con agarre cerrado supino', false, 'wger', '443fec2e-dcca-46fe-ab4a-9a8beb50891e', 'Franpol', ''),
  ('close-grip-supinated-lat-pulldown', 'Close-grip supinated lat pulldown', 'back', null, 'https://wger.de/media/exercise-images/1127/4942b7c0-6bda-4983-88e5-86547c3d445e.png', 'Downward movement • Pull the bar down so that it passes close to your chin and touches the upper part of your chest. • Keep the rest of your body still.', false, 'wger', '4eb41bfb-cbeb-4683-b9c6-902ee7e028e0', 'Franpol', ''),
  ('cable-glute-extension', 'Cable glute extension', 'legs', null, 'https://wger.de/media/exercise-images/1131/3bcf3024-2dcc-4995-9694-55aa2c2e4a9a.png', 'This exercise lets you work the upper, or larger, part of the glutes. For that reason, it should never be missing from your routine of isolated exercises for training the glutes. Stand in front of a cable machine and locate the low pulley. Then attach the ankle strap to work on the low pulley. As for your posture, you should stay upright at all times. Pay special attention to your back to keep it straight and avoid injury. It is advisable to hold on to the machine for better balance. With the leg that is holding the weight of the cable, perform a slow stretch backward without bending the knee.', false, 'wger', '19a9f67b-60f5-4367-9134-b805f3e73956', 'Franpol', ''),
  ('neutral-grip-chest-pulldown', 'Neutral-grip chest pulldown', 'back', null, 'https://wger.de/media/exercise-images/1136/5778a8e9-c606-4843-89c8-9d9469eeb6e4.PNG', 'The lat pulldown is an important exercise for strengthening the back and improving posture, which can contribute to a healthier life. To perform this exercise correctly and avoid injury, it is important to follow a few key steps: Position yourself in front of the cable machine with your knees slightly bent and your feet on the floor. Grip the cable handle with your palms facing each other and your hands shoulder-width apart. Pull the handle down until it touches or comes close to your chest, holding the position for one or two seconds. Slowly raise the handle back to the starting position, making sure to keep your arms and hands straight and your back straight throughout the movement.', false, 'wger', 'eaa7927e-6ea0-4fd5-bbcd-525fe90a184b', 'Franpol', ''),
  ('high-pulley-pullover', 'High-pulley pullover', 'back', null, 'https://wger.de/media/exercise-images/1137/42f22229-c0a0-4bfc-aca6-66fe5e1ab10d.PNG', 'Stand facing the machine, feet slightly apart, gripping the bar with an overhand grip, arms extended, hands shoulder-width apart. Keeping your back fixed and your abdominal muscles contracted, inhale and bring the bar down to your thighs while keeping your arms extended (or your elbows slightly bent). Exhale at the end of the movement.', false, 'wger', 'e87b76b8-2960-4225-9146-47f78bf8c630', 'Franpol', ''),
  ('incline-bench-pulldown', 'Incline bench pulldown', 'back', null, 'https://wger.de/media/exercise-images/1138/6c35fd79-ef35-4cf3-abf5-9c969457b8d4.PNG', 'Lying face down on the incline bench facing the cable machine, perform the pulldown.', false, 'wger', '4e941b0d-4b2f-4393-89cf-6a5e9b69252e', 'Franpol', ''),
  ('arabesque', 'Arabesque', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1141/c7be1cd1-46c5-4a86-a114-5f0fe861c3e0.jpg', 'Take all your weight onto one&nbsp;leg&nbsp;and you''re going to&nbsp;maintain that position, keeping your hips and pelvis level the whole time. With&nbsp;your back in a neutral position you want to tilt yourself forward kicking your leg back up and then slowly with your glutes bring yourself back up to neutral.', false, 'wger', '7dd7a735-c1fe-4ca0-a6e8-e825d897b065', 'cleen', ''),
  ('back-extensi-n', 'Back extensión', 'back', null, 'https://wger.de/media/exercise-images/1143/6e21cb6c-da09-4bcd-b9d2-1ef75237b763.png', 'Espalda en maquina de extensión con peso', false, 'wger', 'deebd257-f84d-4879-9dc4-353ee0ea534f', 'Franpol', ''),
  ('triceps-pushdown', 'Triceps Pushdown', 'arms', null, 'https://wger.de/media/exercise-images/1185/c5ca283d-8958-4fd8-9d59-a3f52a3ac66b.jpg', 'Triceps pushdown on cable using lat bar.', false, 'wger', '6ebb138e-bb0a-402e-84e5-68fe0896e897', 'anto.kreegyr', ''),
  ('one-arm-bent-row', 'One Arm Bent Row', 'back', null, 'https://wger.de/media/exercise-images/1186/1987a039-cf35-437e-bbdc-40c53dd7d053.jpg', 'One arm bent over row on cable with a machine', false, 'wger', '6b6c69bc-0b1e-4b2f-ab61-4945eb18047e', 'anto.kreegyr', ''),
  ('alternating-biceps-curls-with-dumbbell', 'Alternating Biceps Curls With Dumbbell', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1192/651a4535-8210-4dbd-8f06-61d95fdd9963.png', 'Hold two dumbbells, the arms are streched, the hands are on your side, the palms face inwards. Bend one arm at a time and bring the weight with a fast movement up. At the same time, rotate your arms by 90 degrees at the very beginning of the movement. At the highest point, rotate a little the weights further outwards. Without a pause, bring the arm back down, slowly, and do the same with the other arm. Don''t allow your body to swing during the exercise, all work is done by the biceps, which are the only mucles that should move (pay attention to the elbows).', false, 'wger', '94238bef-15ee-42b6-8035-79854b3c6e65', 'Franpol', ''),
  ('russian-twist', 'Russian Twist', 'back', 'Dumbbell, Gym mat, Swiss Ball', 'https://wger.de/media/exercise-images/1193/70ca5d80-3847-4a8c-8882-c6e9e485e29e.png', 'Hold a dumbbell, barbell weight or something else that is heavy with both hands, but make sure it is not too heavy and you are able to keep in form. Lean back to a 45-degree angle from the floor. For an extra challenge, lift your feet off the floor. Rotate your arms to one side to the same level as your chest, touch the floor for a little extra challenge, and then do the same to the other side. When you''re back in your original position after doing both sides it will count as 1 rep.', false, 'wger', '10510fb5-6ebd-4ddc-b03e-423b15deceea', 'lion', ''),
  ('pallof-press', 'Pallof Press', 'shoulders', null, 'https://wger.de/media/exercise-images/1194/074e1766-4208-4a67-a211-9721772d99b0.png', 'The Pallof press is an anti-rotation exercise that trains the larger and smaller muscles around the spine to resist rotation. Stand parallel to the cable machine or to the anchor point to the resistance band and clasp with the handle or band with both hands. Make sure your torso is front on and bring your hands to the center of your chest and slowly press out. Slowly return your hands to the chest and repeat.', false, 'wger', 'e56f2970-e4c9-45eb-8e8c-52abb590e7a6', 'prevail90', ''),
  ('inverted-rows', 'Inverted Rows', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1198/864906ac-4ac7-4e52-a886-c6bb97950a9f.jpg', 'Maintain a straight body, retract your shoulder blades, and pull your chest to the bar for an effective back and upper body workout.', false, 'wger', '8d56eb18-b000-41ff-8b31-c74df3a4b34b', 'Gavru', ''),
  ('claps-over-the-head', 'Claps over the head', 'shoulders', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1223/bf20836a-23b0-4f50-8b98-cfdd97684527.webp', 'Stand with your feet shoulder width apart. Raise your arms and clap over your head', false, 'wger', 'ecf9c0e2-a1d0-4e6e-90e9-5c029e98f2c9', 'Lynn_McIntyre', 'https://www.lyfta.app/exercise/overhead-clap--9mu'),
  ('dumbbell-wide-bicep-curls', 'Dumbbell wide bicep curls', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1225/39a0b7e7-9780-425d-84f5-56d10d1690ac.gif', 'Hold a dumbbell in each hand with your hands slightly wider than shoulder-width apart and palms facing forward. Bend your elbows and lift the dumbbells to your shoulders. Slowly return and repeat.', false, 'wger', 'fd38d854-a244-4646-842b-ef1e0fbfede8', 'Lynn_McIntyre', 'https://www.menshealth.com/uk/how-tos/a748583/dumbbell-bicep-curls/'),
  ('dumbbell-bicep-curl-to-press', 'Dumbbell bicep curl to press', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1226/a6154dbd-67a0-4a36-8748-0f5af3865e83.jpg', 'Bend your elbows and lift the dumbbells to your shoulders. Push the dumbbells over your head while rotating your arms to make your palms face forward. Reverse it to lower down. Repeat the exercise.', false, 'wger', '8675ea3b-0e8b-4a08-9e82-4525ec91dd23', 'Lynn_McIntyre', 'https://www.google.it/search?hl=it&q=Dumbbell+bicep+curl+to+press&tbm=isch&dpr=2#imgrc=aTrt8hKAWIbPzM&imgdii=Pqr5Qm81Bk-vkM'),
  ('dumbbell-rear-delt-row', 'Dumbbell rear delt row', 'shoulders', 'Dumbbell', 'https://wger.de/media/exercise-images/1227/57415c3c-2963-4130-9f6f-79f6a96113b6.gif', 'Hold a dumbbell in each hand. Bend at your hips to make your back almost parallel to the floor. Let your arms hang down. Keep your arms in line with your shoulders. bend and lift your elbows out to the sides until your upper arms are parallel to the floor. Slowly return and repeat', false, 'wger', 'adb6067f-fd48-4a25-a9b4-0793c5f158fa', 'Lynn_McIntyre', ''),
  ('triceps-stretch-left', 'Triceps stretch left', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1230/9fd1e2fd-f2c4-432d-b3ae-5e5f24085777.webp', 'Put your left hand on your back, use your right hand to grab your left elbow and gently pull it. Hold this position for a few seconds.', false, 'wger', 'aa72741d-17ae-410e-b49a-1df7aaf0afe1', 'anonymous', ''),
  ('triceps-stretch-right', 'Triceps stretch right', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1231/b10457ce-5fa5-4d20-a32f-3c7100c6a9d9.webp', 'Put your right hand on your back, use your left hand to grab your right elbow and gently pull it. Hold this position for a few seconds.', false, 'wger', '1b9968f4-a00b-4157-8847-1c3c7dbb0d5a', 'anonymous', ''),
  ('standing-biceps-stretch-left', 'Standing biceps stretch left', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1232/2b6de046-5806-49e3-bf36-b6fae16af021.png', 'Stand with your left arm close to a wall. Extend your left arm and put your left hand on the wall, then gently turn your body to the right.', false, 'wger', 'a569e8c3-218f-40db-9d71-e155c68cb26e', 'anonymous', ''),
  ('standing-biceps-stretch-right', 'Standing biceps stretch right', 'chest', null, 'https://wger.de/media/exercise-images/1233/d7d6f9e1-7834-4cca-bd3b-f9def33ff44d.png', 'Stand with your right arm close to a wall. Extend your right arm and put your right hand on the wall, then gently turn your body to the left.', false, 'wger', '671568f9-6653-4e11-ac71-3f34c74329a0', 'anonymous', ''),
  ('finger-pushup', 'Finger Pushup', 'arms', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1217/590e65db-de60-4727-b7eb-55f80af56043.png', 'Hand Positioning: Start in a plank position with your hands directly beneath your shoulders. Spread your fingers wide apart, placing them firmly on the ground. Finger Placement: Gradually lift your palms off the ground, shifting the weight onto your fingers. Focus on distributing the load evenly across your fingertips and thumbs. Body Alignment: Maintain a straight line from head to heels to engage your core. Keep your body in a controlled and stable position throughout the exercise. Lowering Phase: Slowly bend your elbows, lowering your chest towards the ground. Ensure controlled movement, maintaining stability on your fingertips. Pushing Up: Press through your fingertips to straighten your arms, returning to the starting position. Emphasize the engagement of your fingers and thumbs throughout the push-up.', false, 'wger', '676e8149-863e-4174-a09a-a327b247c00d', '', ''),
  ('standing-calf-stretch', 'Standing Calf Stretch', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1239/5026373a-a7b4-4e26-a0aa-c46634205196.jpg', 'This stretch targets the gastrocnemius (the chief muscle of the calf of the leg, which flexes the knee and foot). It is easy to perform anywhere. All you need is a wall or a chair.', false, 'wger', 'f36dfa40-7586-4721-a434-1fd878232c62', 'erikocobra', 'https://www.flickr.com/photos/mdandersonfocused/'),
  ('seated-cable-row', 'Seated Cable Row', 'back', null, 'https://wger.de/media/exercise-images/1117/2555c4c3-a84d-47db-b83b-cbf721f12e45.png', 'Take a seat on the machine with your feet planted, a little wider than shoulder width. Drive the heels, and squeeze the glutes. Grab onto the cable handle. Sit up tall with a slight bend through the knees. Tighten up the abs and low back to maintain a perpendicular angle to the floor with your torso. Roll the shoulders back and down. Squeeze them together as you row, thinking about pinching a pencil in between them. As you do this, pull the handle back towards you, landing right above your belly button. Pause here for a moment before returning the handle, still squeezing the shoulder blades. Once you''ve returned the weight to the stack, then allow the shoulder blades to relax, without pulling the torso forward. Repeat the movement.', false, 'wger', '0ecfec6f-5d0f-4e8a-8d37-f6203a8923b8', 'Franpol', ''),
  ('double-leg-calf-raise', 'Double Leg Calf Raise', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1243/53d4fabe-c994-4907-873f-8d82813a9832.png', 'The double leg heel raise is important to strengthen and create control and stability around the ankle and knee, and provide balance and control for the hip and pelvis.', false, 'wger', '58ca3e51-ea64-4771-a74a-a74d29f5c40c', 'erikocobra', 'https://commons.wikimedia.org/wiki/File:Exercise_Heel_Raise_Two_Legs.png'),
  ('sitting-calf-stretch-dorsiflexion', 'Sitting Calf Stretch (Dorsiflexion)', 'legs', null, 'https://wger.de/media/exercise-images/1274/bcffdf52-3c36-4b0c-b787-fb84f20bf82d.png', 'This is a light stretch for the calf that is great for rehab.', false, 'wger', '9f9bfa54-4702-4eb1-a72a-0fc12c846c72', 'erikocobra', 'https://www.tims.nhs.uk/wp-content/uploads/2020/06/6.18-TIMS-Calf-Muscle-Injury-Draft.pdf'),
  ('plantarflexion-stretch-with-band', 'Plantarflexion Stretch with Band', 'legs', null, 'https://wger.de/media/exercise-images/1275/0652d306-93eb-42f0-b564-7c3261ea809a.png', 'This stretch is for the ankles, as well as Tibialis anterior.', false, 'wger', 'f397656d-6f26-47c6-9e4c-221687f3f2fa', 'erikocobra', ''),
  ('incline-chest-supported-dumbbell-row', 'Incline Chest-Supported Dumbbell Row', 'back', 'Bench, Dumbbell', 'https://wger.de/media/exercise-images/1283/e7262f70-7512-408a-8d00-4c499ef632fc.jpg', 'Set up an adjustable bench at a 45-degree angle. Lay on your stomach with your head hanging just above the edge of the bench. Grab a dumbbell in each hand and set up with a good posture – core and lats engaged and shoulders neutral. Row the dumbbells toward the top of the stomach and squeeze the back at the top of the rep. Finally, lower the dumbbells back to the starting position and repeat until all reps are completed.', false, 'wger', '51a2d520-b510-4b6e-bd65-9fc40365e8de', 'carlos3c', 'https://hivamf.tistory.com/entry/%EC%9D%B8%ED%81%B4%EB%9D%BC%EC%9D%B8-%EB%B2%A4%EC%B9%98-%EB%8D%A4%EB%B2%A8-%EB%A1%9C%EC%9A%B0Incline-Bench-Dumbbell-Row'),
  ('talons-fesses', 'Talons fesses', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1285/1ab8005d-41e4-4505-9a7d-5277d59bb3cd.jpg', 'Touch your heels to your buttocks, while remaining static or moving', false, 'wger', '42657bd4-bf4e-4429-8e6a-2f5f585aa22a', 'painDpice', 'https://www.ete-indien-editions.fr/articles/comment-bien-echauffer-quand-on-est-senior/'),
  ('reverse-grip-barbell-curls', 'Reverse Grip Barbell Curls', 'arms', 'Barbell', 'https://wger.de/media/exercise-images/1290/c05818bf-1c81-46df-9f24-42e354265388.png', 'Hold the barbell with an overhand grip (palms facing down) approximately shoulder-width apart. Ensure your back is straight, shoulders slightly pulled back, and arms fully extended. Curl the barbell upwards towards your chest in a controlled motion, keeping your elbows close to your body. The motion should be smooth without any swinging or momentum use. Once the barbell is at chest level, pause briefly to maximize contraction in the biceps and forearms. Slowly lower the barbell back to the starting position with a controlled movement, fully extending your arms.', false, 'wger', 'dd6e8753-a574-476e-900a-b794eb592e7b', 'Franpol', ''),
  ('low-cable-cross-over-nb', 'Low-Cable Cross-Over - NB', 'chest', null, 'https://wger.de/media/exercise-images/1296/c42782fe-337a-44f4-9079-7f6dedab4885.png', 'The low-cable cross-over is an isolation movement that uses a cable stack to target the upper portion of the pectoral muscles. It is common in upper-body and chest-focused muscle-building workouts, often in combination with presses or flyes from other angles to target all portions of the chest.', false, 'wger', 'ac6e6a09-5175-4fea-9e56-e2ff3c00b0f2', 'JackSparrow', ''),
  ('high-cable-cross-tricep-extention-nb', 'High-Cable Cross Tricep Extention - NB', 'arms', null, 'https://wger.de/media/exercise-images/1298/ec4b83ec-5a8f-4303-9050-99ec4389bc2a.png', 'The high-cable cross tricep extension is an isolation exercise for targeting the triceps, particularly the long head. It utilizes cables and handles grasped with opposite hands, allowing for a unique pressing motion that can be effective for building tricep strength. Unlike exercises that use a straight bar or rope, this variation can be more comfortable on your wrists and elbows', false, 'wger', '4ef75e13-c058-4410-91c0-2f2d2df98130', 'JackSparrow', ''),
  ('lateral-push-off', 'Lateral Push Off', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1325/d8372291-6725-452a-9711-6321c061e354.jpg', 'Push off the ground and land on one leg and regain balance before jumping to the other leg', false, 'wger', '45e44940-d4a0-4c66-8cbb-7afe785d5610', 'cleen', ''),
  ('forearm-curls-underhand-grip', 'Forearm Curls (underhand grip)', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1333/89f43354-32e3-473a-9bcf-caca51f1a8e3.webp', 'Engage the muscles Don''t use momentum Controlled movement Slow movement', false, 'wger', '17947bd2-db2d-4ba6-998c-1bbf31cf228a', '', ''),
  ('triceps-overhead-dumbbell', 'Triceps Overhead (Dumbbell)', 'arms', 'Dumbbell', 'https://wger.de/media/exercise-images/1336/ebf88217-df26-4ef7-94cb-f0c2220c6abe.webp', 'Keep the elbows fixed Engage the muscles Don''t use momentum Controlled movement Slow movement Don''t overextend', false, 'wger', '19133a0d-e6b2-4d57-8a84-8aac3d962a99', '', ''),
  ('shoulder-raise-dumbbell', 'Shoulder Raise (Dumbbell)', 'shoulders', 'Dumbbell', 'https://wger.de/media/exercise-images/1338/9d157b4d-5af0-43c1-bd34-f52144ba1b54.webp', 'Engage the muscles Don''t use momentum Controlled movement Slow movement Always keep the arms bent Don''t overextend', false, 'wger', '9a644b0e-8691-4216-b2cc-f058f58ec96d', '', ''),
  ('lower-back-extensions', 'Lower Back Extensions', 'back', null, 'https://wger.de/media/exercise-images/1348/a3769120-2445-49f2-97d3-afc1238bfc2a.webp', 'Engage the muscles Lift your bottom slightly Controlled movement Slow movement Don''t use momentum Keep your upper body straight', false, 'wger', '50a8f1f6-6772-4319-be9d-3bad1374dadf', '', ''),
  ('dumbbell-hex-press', 'Dumbbell Hex Press', 'chest', 'Dumbbell', 'https://wger.de/media/exercise-images/1353/138cb483-7d4d-4519-b029-63e4269810a6.webp', 'Engage the muscles Position your feet wide Controlled movement Slow movement Bring the weights toward your lower chest/stomach', false, 'wger', '587af8f1-516b-44c3-8660-70f262e1bef8', '', ''),
  ('blackroll', 'Blackroll', 'back', null, 'https://wger.de/media/exercise-images/1363/1dba566b-e799-4bde-abb0-c011a3c75e52.webp', 'Controlled movements Slow movements Don''t use momentum', false, 'wger', '1fe103e2-1def-41de-8eab-e2e11296446d', '', ''),
  ('torso-twist', 'Torso Twist', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1377/12e7a231-d36a-4992-bf57-ff7bfe0f3ae4.jpg', 'Standing Torso Twist WorkoutTarget your core and improve flexibility with this dynamic standing exercise! The Standing Torso Twist Workout involves twisting your torso while keeping your feet and hips stable, engaging your obliques, and stretching your entire upper body. This movement helps to:Strengthen core musclesIncrease flexibility in the spine and torsoImprove posture and balanceEnhance overall athletic performancePerform 3 sets of 10-15 reps, twisting to each side, to feel the benefits of this effective and efficient workout!', false, 'wger', '56a03260-2901-4b28-bd41-a030185f985a', 'brucem', 'https://workoutguru.fit/exercises/standing-torso-twist-female-video-exercise-guide-tips-735512/'),
  ('hamstring-kicks', 'Hamstring Kicks', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1387/a2cf7eda-5540-4105-b30e-1c2f2679a6c7.png', 'Stand with your feet hip-width apart and extend one arm in front of you. Swing that leg up in front of you and back down while keeping your leg as straight as possible and your toes pointed up.Repeat with the other leg.', false, 'wger', '66aef559-02e8-4f35-91f6-600f103e9cbf', 'captive0592', ''),
  ('cable-lateral-raises-single-arm', 'Cable Lateral Raises (Single Arm)', 'shoulders', null, 'https://wger.de/media/exercise-images/1378/7c1fcf34-fb7e-45e7-a0c1-51f296235315.jpg', 'The single arm cable lateral raise is a variation of the lateral raise and an exercise used to build the muscles of the shoulders. Position a cable at the lowest position possible and attach a single handle. Reach across your body and grab the handle with a neutral grip. Keep the elbow slightly bent and pull the handle across your body and raise laterally. Slowly lower the handle back to the starting position under control.', false, 'wger', '81942f3d-d92c-431c-b9d0-0da12918d1e4', 'carlos3c', 'https://commons.wikimedia.org/wiki/File:Girl_doing_one_arm_shoulder_raise.jpg'),
  ('good-morning', 'Good Morning', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1392/a02c9c7d-f42d-43e0-9946-1b99b014daee.png', 'Stand with your feet more than shoulder-width apart (wider stance) and place your hands on your hips. Hinge at your hips and lower your upper body towards the ground while keeping your back straight then come back up.', false, 'wger', '77a56810-d050-4083-9501-d648f773376a', 'Everkinetic', ''),
  ('seated-w-curl', 'Seated W Curl', 'arms', 'Bench, Dumbbell', 'https://wger.de/media/exercise-images/1448/2184e68c-32b5-413f-a7c1-4a2d1bb98c35.png', 'Sit on bench with 60° incline Hold dumbbells beside body near the ground, palms facing outwards, arms fully extended Move dumbbells up using only biceps and without momentum', false, 'wger', 'ecc46519-94b8-4ecc-b5b8-973e753e98a6', '', ''),
  ('knee-to-chest-stretch', 'Knee to Chest Stretch', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1452/85a6b9de-4eec-445b-8ebb-f1950b076aba.png', 'The knee to chest stretch is a simple yet effective exercise for relieving lower back tension and improving hip mobility. To perform, lie flat on your back with your legs extended. Bring one knee toward your chest, wrapping your hands around your shin or behind your thigh. Gently pull the knee closer to your chest while keeping the other leg straight on the floor. Hold the stretch for 15–30 seconds, then switch sides. For a deeper stretch, both knees can be pulled toward the chest simultaneously.', false, 'wger', '492e90a5-1ecb-4a06-8e9d-26a00042560e', 'Davidgj32', ''),
  ('sit-up-elbow-thrust', 'Sit Up Elbow Thrust', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1479/0305d98e-0887-4c0c-8992-7c220814efc2.webp', 'This is a top down rotation movement, and it’s a bit more explosive, too. Lying with knees bent and feet on the floor, sit up and then drive your left elbow across your entire body toward the right, then come back to center and then finally lower yourself down. Then hit the other side.', false, 'wger', '5af00591-2d77-4ea6-a347-825ad18beff1', '', ''),
  ('overhead-triceps-extension', 'Overhead Triceps Extension', 'arms', 'SZ-Bar', 'https://wger.de/media/exercise-images/1519/fab7f641-27d4-40b5-8edd-1a0a137bfd94.gif', 'Overhead Triceps Extension with EZ Bar – Quick Guide The overhead position emphasizes the long head of the triceps (because it''s stretched under load), the exercise does engage all three triceps heads (long, lateral, and medial) to some degree during extension. Setup: Sit on a bench (or stand) and hold an EZ bar with a narrow, overhand grip. Lift the bar overhead, arms fully extended. Keep your core tight and elbows close to your head. Execution: Slowly lower the bar behind your head by bending your elbows until they reach ~90°. Keep elbows pointed forward (not flaring out). Finish: Extend your arms back up to the starting position, squeezing your triceps at the top. Tips: Control the movement to avoid straining your shoulders. Use a moderate weight for full range of motion. Keep your back straight and avoid arching.', false, 'wger', 'c5797bdf-1aa1-4d51-9775-c929ec5a2aaf', 'benjamin.yildiz@proton.me', 'https://indonesian-recipes.com/download/2030-version.html'),
  ('pendular-hack', 'Pendular hack', 'legs', null, 'https://wger.de/media/exercise-images/1521/e4e4aa78-3c96-4b1d-95c0-f9f73a0779d0.webp', 'Pendulum hack, made on a pendulum machine', false, 'wger', 'daaf1459-e748-4c95-8990-ed3101b2e20d', 'polloperro', ''),
  ('bulgarian-squat-with-dumbbells', 'Bulgarian Squat with Dumbbells', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1706/0c5243cc-2539-4005-aee0-d3a8c5d3a32c.jfif', 'The Bulgarian split squat consists of performing a squat on one leg with the rear foot resting on a raised platform. Elevating your back leg on a bench creates instability and increases the range of motion of the exercise.', false, 'wger', '60d2c34b-43a1-48a3-b43b-160e4c0157f2', 'AlucardEvil40', ''),
  ('clap-push-up', 'Clap Push-UP', 'chest', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1554/49207a62-8799-4b47-8c0b-7bde02926f3d.png', 'The clap push-up is an explosive upper body movement that builds power and fast-twitch muscle strength. It adds a plyometric challenge to the traditional push-up by requiring the hands to leave the ground mid-rep. Start in a strong push-up position with your hands slightly wider than shoulder-width and core engaged Lower your body explosively and push off the ground with enough force to lift your hands. Quickly clap your hands together at chest level before returning them to the floor. Land with soft elbows to absorb the impact and immediately move into the next rep', false, 'wger', 'fdeb0973-121f-494d-8b94-54f1d7ba003f', 'Settebello', ''),
  ('devil-s-press', 'Devil’s Press', 'chest', 'Dumbbell', 'https://wger.de/media/exercise-images/1556/a23c820b-e08b-4911-a6a4-80f16c15d2e0.png', 'The Devil’s Press is a hybrid movement combining a dumbbell burpee and a double dumbbell snatch. It’s a full-body, high-intensity exercise that develops strength, power, and metabolic conditioning. Start with a dumbbell in each hand and perform a burpee, letting your chest touch the ground while holding the dumbbells. Explosively jump your feet forward and swing the dumbbells between your legs. Drive the dumbbells overhead in one continuous motion, locking out your arms. Lower the dumbbells with control to return to the starting position and repeat', false, 'wger', 'bb9b994e-426f-4693-9d16-3f8d5a9c72b8', 'Settebello', ''),
  ('bird-dog', 'Bird Dog', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1572/3d14e761-a73d-49da-8804-f3016a7573ff.png', 'The Bird Dog is a core stability exercise that enhances balance, coordination, and spinal alignment. It’s a low-impact movement ideal for strengthening the posterior chain and improving overall functional control. Begin on all fours with hands under shoulders and knees under hips, keeping your spine neutral. Extend your right arm forward and left leg backward simultaneously, keeping hips square. Pause briefly at full extension while engaging your core and glutes. Return to the starting position and repeat on the opposite side', false, 'wger', '6349365e-e901-4280-a1b7-65734986f47d', 'Settebello', ''),
  ('ab-wheel', 'Ab wheel', 'core', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1573/a9ab402b-61ef-4d60-b91a-df52bf7f41a9.jpg', 'Starting Position: Kneel on the floor with the ab wheel in front of you. Grip the Wheel: Hold the handles firmly. Roll Out: Slowly roll the wheel forward, extending your body while keeping your core tight. Return: Pull the wheel back towards your knees, maintaining tension in your core.', false, 'wger', '203a6fee-7436-4313-858f-c1e364136793', '', ''),
  ('trap-press', 'Trap press', 'shoulders', 'Barbell, Bench, Dumbbell', 'https://wger.de/media/exercise-images/1581/b71a6710-5798-4639-ac5a-22a2cdae2036.jpg', 'Laying flat with arm pointing straight upwards, elbow fully extended, use only your shoulder to raise the weight as high as comfortable and back to rest.', false, 'wger', '41b9f5a5-73de-414d-b08a-54025eccedc6', '', 'https://orthop.washington.edu/patient-care/articles/shoulder/home-exercises-for-the-unstable-shoulder.html'),
  ('side-laying-interior-rotation', 'Side-laying interior rotation', 'shoulders', 'Barbell, Bench, Dumbbell', 'https://wger.de/media/exercise-images/1582/5094fe30-eea2-4269-b0de-4b8a20558fd7.png', 'Laying on your side and using the arm closest to the bench, maintain a 90 degree bend at the elbow and allow the weight to fall towards the ground past the bench as low as comfortable. Bring the weight up using only rotation of the shoulder to the opposing shoulder.', false, 'wger', 'd9c1f78c-7bf6-4e6a-92e4-7bf4ed4a0a67', '', ''),
  ('smith-machine-split-squat', 'Smith Machine Split Squat', 'legs', 'Barbell', 'https://wger.de/media/exercise-images/1593/9815fcd6-cf40-4ddd-9b38-2eac25973de1.gif', 'The "Smith Machine Split Squat" is a strength exercise performed on the Smith machine, ideal for targeting the legs and glutes. It involves placing one foot forward and the other back, lowering the body until the front thigh is parallel to the ground while the bar slides vertically along the machine. This exercise helps improve stability, correct muscle imbalances, and reduces stress on the back, providing a safe environment for strength training.', false, 'wger', 'b382dcb2-60a8-412d-b0ee-6afe9c9f36d7', '', 'https://www.docteur-fitness.com/split-squat-a-la-smith-machine'),
  ('sliding-lateral-lunge', 'Sliding Lateral Lunge', 'legs', 'Barbell', 'https://wger.de/media/exercise-images/1604/7695428e-bfed-4021-b987-498d93153995.png', 'Stand upright with your feet hip-width apart, holding a kettlebell close to your chest in goblet position. Place one foot on a slider, gliding disc, or towel. Keep your chest tall and core engaged. Slowly slide the foot outward to the side while bending the opposite knee, lowering your hips into a lateral lunge. Keep the working leg’s knee aligned with the toes and avoid letting it collapse inward. The non-working leg remains straight and slides smoothly along the floor. Push through the heel of the bent leg to return to the starting position while maintaining control of the kettlebell.', false, 'wger', '55bb8725-a7c9-48a0-b192-ec6c9db6f9bc', 'RiccaBaro', ''),
  ('seated-row-machine', 'Seated Row (Machine)', 'back', null, 'https://wger.de/media/exercise-images/1725/f0ebd44e-b8e1-400c-b598-ca371f3a07af.png', 'Keep your chest up and squeeze your shoulder blades at the end. Don’t hunch forward or round your back during the pull.', false, 'wger', '9bcc7b4f-4172-4db7-be95-d7b659c486f5', 'barry', ''),
  ('kettlebell-sumo-deadlift', 'kettlebell sumo deadlift', 'legs', 'Kettlebell', 'https://wger.de/media/exercise-images/1612/3dc33f57-2786-4305-8b91-e011d7055923.jpg', 'Place your feet wider than shoulder-width apart, pointing your toes outward. Keep your back straight, shoulders back, and chest up. The knees must follow the same direction as the toes and not move forward. When going up, it is advisable to contract your glutes to maximize the effectiveness of the exercise..', false, 'wger', '5cbaa028-114d-4a15-9a95-70d9b3146f30', '', ''),
  ('rubber-band-glute-kickback', 'rubber band glute kickback', 'legs', 'Resistance band', 'https://wger.de/media/exercise-images/1613/a851fe9d-771f-44da-82f0-799e02ae3fd1.jpg', 'A rubber band glute kickback is an exercise performed on hands and knees, where you anchor a resistance band to your foot and kick your heel back and up, squeezing your glute at the top of the movement, while maintaining a stable core and flat back to target and strengthen the gluteal muscles.', false, 'wger', '4221c8af-b3ca-4a53-9176-bd66e46d10f2', '', ''),
  ('treadmill-cardio', 'Treadmill Cardio', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1615/7792295c-83b6-4ea8-9353-ce02f0ad2559.jpg', 'It''s a cardiovascular workout performed on a treadmill to improve endurance, burn calories, and promote heart health. It offers multiple benefits, such as the ability to easily adjust speed and incline, allowing for a variety of workouts, from hill walking to high-intensity interval training (HIIT) and tempo runs. To optimize results, it''s important to vary your workouts. Benefits of Treadmill Cardio: Improved Cardiovascular Health: Regular aerobic exercise on a treadmill strengthens the heart and lungs, which can help prevent heart disease. Weight Loss: By burning calories, treadmill training can be an effective tool for weight loss and maintaining a healthy weight. Muscle Strengthening: It strengthens the muscles in the legs and glutes, helping to prevent muscle loss, which is especially important with age. Training Flexibility: Allows you to vary speed, incline, and intervals, making your workout more dynamic and adaptable to different fitness levels. Types of Treadmill Training: Hill Walking: Increasing the incline of the treadmill and walking at a brisk pace can improve endurance and work your leg muscles. Endurance Jog: A run at a comfortable, steady pace that keeps your heart rate in a target zone (such as Zone 2) to build endurance. Interval Training: Alternating periods of high intensity (fast running) with periods of low intensity (easy walking or jogging) to maximize calorie burn and cardiovascular improvement. Tempo Run: A run at a steady, sustained pace that is slightly faster than a normal jog, which challenges your ability to sustain a more intense effort for an extended period.', false, 'wger', '3f8e5871-4895-48c9-928d-dc1bc134f57b', '', ''),
  ('dumbbell-donkey-kick', 'Dumbbell donkey kick', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1616/97e6fd98-2ca6-486f-b9b2-f0499fe38044.jpg', 'The dumbbell donkey kick is an effective exercise for working the glute and hamstring muscles. This exercise is usually performed on all fours, using a dumbbell to add resistance. The steps for performing it correctly are described below. Starting position: Get on all fours on a mat, with your hands aligned under your shoulders and your knees aligned under your hips. Placing the dumbbell: Take a dumbbell and place it behind the knee of the leg you are going to lift. Make sure it is held securely to prevent it from falling during the exercise. Exercise: Inhale and, as you exhale, lift the leg with the dumbbell upward, keeping the knee bent at a 90-degree angle. Raise the leg until it is parallel to the floor, feeling the contraction in the glutes. Hold the position for one second at the top and then slowly lower the leg back to the starting position. Repetitions: Perform 10 to 15 repetitions per leg, making sure to maintain good form throughout the exercise. Sets: Complete 2 to 3 sets, depending on your fitness level.', false, 'wger', '2539f907-0c10-4af5-807c-48cd15fd0878', '', ''),
  ('stationary-bike-cardio', 'Stationary bike cardio', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1618/c18baedc-ff98-4fb2-b4f5-38a05c12f637.png', 'Benefits of Stationary Bike Cardio Stationary bike cardio is an excellent form of exercise that offers multiple benefits for health and well-being. Here are some of the most notable ones: Improved Cardiovascular Health Strengthens the heart: Regular exercise helps improve the heart''s efficiency and reduce the risk of cardiovascular disease. Increases circulation: It improves blood flow, which can help lower blood pressure. Calorie Burning and Weight Loss Efficient for burning calories: Depending on the intensity, you can burn between 400 and 600 calories per hour. Helps with weight loss: Combined with a balanced diet, stationary bike cardio can be effective for losing weight. Muscle Strengthening Tones the legs: It mainly works the leg muscles, including the quadriceps, hamstrings and calves. Improves muscular endurance: Over time, you can increase the endurance and strength in your legs. Mental Health Benefits Reduces stress: Exercise releases endorphins, which can improve your mood and reduce stress. Boosts energy: Regular physical activity can raise your energy levels and improve sleep quality.', false, 'wger', '5da3d393-0c4e-4ac8-96b4-aab51f6ab3d1', '', ''),
  ('straight-arm-pulldown-cable', 'Straight-Arm Pulldown (Cable)', 'back', null, 'https://wger.de/media/exercise-images/1726/2e7e541b-5f55-405a-ae78-3e71b3f42db4.png', 'Keep arms straight but not locked, pulling with your lats, not your shoulders. Don’t let your shoulders shrug up during the movement.', false, 'wger', 'a45123c6-34c2-43cf-b6bf-914a8f40995a', 'barry', ''),
  ('seated-dumbbell-calf-raise', 'Seated Dumbbell Calf Raise', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1620/edd40e39-e337-4460-a8dd-6127d40ddd16.jpeg', 'The seated dumbbell calf raise is a targeted exercise for strengthening the lower leg muscles. It follows the same movement pattern as the machine version: you place the weight on your knees, and by extending and flexing your ankles, you move the weight.', false, 'wger', '6995c30a-037f-4de3-ac4a-45384a1f38f9', 'AlucardEvil40', 'https://training.fit/exercise/seated-dumbbell-calf-raise/'),
  ('unilateral-cable-row', 'Unilateral Cable row', 'back', 'Bench', 'https://wger.de/media/exercise-images/1621/ca1bc68d-9c36-4dd3-8ec4-496c57b5c564.jpg', 'Put a vertical seated bench in front of the cable row machine.position it so that you can focus on one side, and then do slow pulls focusing on the lateral muscles and ensuring tention in those muscles when in a stretched position.', false, 'wger', 'c1a9297d-6786-45dc-9047-5539fb61db9c', 'technofer', ''),
  ('face-pulls-with-yellow-green-band', 'Face pulls with yellow/green band', 'back', 'Resistance band', 'https://wger.de/media/exercise-images/1732/d13b9adb-968e-4f73-95e6-b16690bcf616.jpg', 'Face pulls with band – standing horizontal pull. Grab the band at face height, pull elbows high and wide towards your face while squeezing shoulder blades together. Trains upper back, rear shoulders and improves posture.', false, 'wger', '7bf4e131-d4a3-44c0-8fca-9e10002492e7', '54str', ''),
  ('isometric-squat-to-failure', 'Isometric Squat to Failure', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1733/4ef77069-beb2-4504-a4f3-b181d5f35212.png', 'sometric Squat to Failure: A Strength Training Technique Definition The isometric squat to failure is a variation of the squat exercise where you hold a static squat position at a specific angle, maintaining the position until your muscles can no longer sustain the contraction.', false, 'wger', '06cb77ba-e56d-4422-bc14-77cc367c9fd8', 'Tierrasverdes', ''),
  ('single-leg-lunge-with-kettlebell', 'Single-Leg Lunge with Kettlebell:', 'legs', 'Kettlebell', 'https://wger.de/media/exercise-images/1734/782e2fbb-1267-476d-a817-14f3b83e0564.png', 'How to do a single-leg kettlebell lunge Preparation: Stand with your feet together. Hold the kettlebell with both hands by the handle, keeping it close to your chest, or hold it with one hand (on the same side as the working leg). Step and Lower: Take a large step forward (or backward, which is safer for your knees) with one leg, lowering your hips until both knees form a 90-degree angle. Focus: Shift your weight onto your front (or bent) leg, keeping your back straight and your torso upright. Return: Push off with your front leg to return to the starting position.', false, 'wger', 'ff6c2fb1-5105-49ba-babe-c0d403940269', 'Tierrasverdes', ''),
  ('single-leg-side-glute-press', 'Single-leg side glute press', 'legs', 'Incline bench', 'https://wger.de/media/exercise-images/1735/43bca7d9-2333-43f3-8554-2d0b39fa2a07.png', 'The Single-Leg Side Glute Press is a leg press machine variation where you angle your body sideways on the pad, placing one foot high and slightly angled to press the weight, powerfully targeting the outer glute (gluteus medius/minimus) and hamstrings for balanced leg development and stability, requiring focus on pushing through the heel and maintaining control without locking out. How to Perform: Setup: Sit in the leg press machine, rotate your body to one hip, placing one foot high on the platform at about a 45-degree angle with toes pointed slightly out/forward. Positioning: Keep your hip, knee, and ankle aligned, and ensure your lower back stays on the pad. Descent: Slowly lower the weight, allowing your knee to bend deeply (near 90 degrees), feeling a stretch in your glute and hamstring. Press: Drive through your heel (not your toes) to press the weight back up, squeezing your glutes and hamstrings, stopping just before your leg fully extends. Control: Avoid bouncing and don''t let your lower back lift off the pad; maintain tension throughout the movement.', false, 'wger', 'd28cf04f-4077-484b-82ed-abaea8d4053d', 'Tierrasverdes', ''),
  ('neutral-grip-pull-ups-or-trx-rows', 'Neutral-grip pull-ups or TRX rows', 'back', 'Pull-up bar', 'https://wger.de/media/exercise-images/1738/0529acdf-ede8-42a2-a3e5-8d0c57b7a0e1.jpg', 'Pull-Up: Vertical Pull — Focuses more on the Lats (back width). TRX Row: Horizontal Pull — Focuses more on the Rhomboids/Traps (mid-back thickness and posture).', false, 'wger', '15fda45b-108b-4b28-bfe5-d0e55a0914bf', '54str', ''),
  ('machine-side-lateral-raises', 'Machine Side Lateral Raises', 'shoulders', null, 'https://wger.de/media/exercise-images/1744/cb9263c4-39fc-4261-8d30-a5d6d57841c1.jpg', 'Machine side lateral raises are an isolation exercise for the side (lateral) deltoids, performed on a machine for stability, targeting the outer shoulder by lifting pads or handles out to the sides to shoulder height, then lowering slowly, keeping elbows slightly bent and traps down to focus on the delts. This exercise helps build shoulder width by preventing swinging and providing constant tension, making it great for beginners or as a finisher. How to Perform Machine Lateral Raises Setup: Adjust the seat so your shoulders align with the machine''s pivot point, your chest is against the pad (or back if facing out), and your arms are at a 90-degree angle with the pads/handles. Starting Position: Grip the handles with a relaxed grip, elbows slightly bent, and shoulders down (depressed) away from your ears. Lifting Phase: Exhale and lift your arms out to the sides, moving your upper arms laterally, until they are parallel to the floor. Peak Contraction: Pause briefly at the top, squeezing the side delts, but don''t shrug your shoulders up. Lowering Phase: Inhale and slowly lower the weight back down with control, resisting the weight on the way down.', false, 'wger', 'dc87b735-016c-410b-915c-e3521fea4be7', '', ''),
  ('cable-front-raise-with-a-small-bar', 'Cable Front Raise with a small bar', 'shoulders', null, 'https://wger.de/media/exercise-images/1745/9c92843a-6b90-428b-a868-9af4b11bad38.jpg', 'The Cable Front Raise with a small bar isolates your anterior deltoids (front shoulders) by providing constant tension, requiring you to stand facing away from a low pulley, grab the bar with an overhand grip, and lift it in front of you to shoulder height with slightly bent arms, avoiding swinging and keeping your core tight for controlled movement up and down. Use a light-to-moderate weight, focusing on slow, controlled reps to feel the muscle work, not momentum. How to Perform the Cable Front Raise (Bar) Setup: Attach a small straight bar to a low cable pulley. Set the weight to a light or moderate setting. Starting Position: Stand with your back to the machine, holding the bar with an overhand grip (palms facing down) at hip level, arms extended but not locked. Feet shoulder-width apart, core braced, shoulders back and down. The Lift: Exhale and slowly raise the bar straight up in front of you, keeping a slight bend in your elbows, until your hands reach shoulder height (or slightly below). The Hold: Pause briefly at the top, squeezing your front delts. The Lower: Inhale as you slowly and controllably lower the bar back to the starting position, maintaining tension.', false, 'wger', '6e03ecb3-6bfe-4b34-be9d-e5c33e820cc6', '', ''),
  ('smith-machine-squat', 'Smith machine squat', 'legs', null, 'https://wger.de/media/exercise-images/1747/af9647dd-04ec-4adf-9c07-4e33edb77277.jpg', 'Technique and Execution The Smith machine squat is a variation of the traditional barbell squat that uses a guided, fixed-path barbell. Here''s a detailed breakdown of the proper technique: Starting Position Foot Placement: Position feet slightly forward of the bar, about shoulder-width apart Bar Position: Rest the bar on your upper trapezius/shoulders, similar to a traditional back squat Stance: Feet can be slightly angled outward for natural hip rotation Squat Movement Unrack the bar by rotating it to release from the safety hooks Slowly lower your body by bending knees and hips Descend until thighs are parallel to the ground (or slightly below) Pause briefly at the bottom of the movement Drive through your heels to return to the starting position Benefits and Considerations Advantages Reduced Balance Requirements: Fixed bar path makes it easier for beginners Controlled Movement: Less risk of improper form compared to free weight squats Isolation: Allows focused leg muscle development', false, 'wger', 'f3ef220b-a070-449c-a463-876d30cd9b14', '', ''),
  ('single-leg-deadlift-with-dumbbell', 'Single-Leg Deadlift with Dumbbell', 'legs', 'Dumbbell', 'https://wger.de/media/exercise-images/1736/aa724cc5-c485-4f3e-9d2a-0c6ae4baefbe.png', 'Starting Position: Stand upright with a slight bend in your knees, holding a dumbbell in one or both hands. Shift your weight onto your supporting leg (e.g., your right leg) and lift your non-supporting foot slightly off the floor. The Hinge: Keeping your back flat and core engaged, hinge at your hips, pushing your glutes backward. As your torso lowers, extend your non-supporting leg straight back behind you for balance, keeping your hips square to the floor. The dumbbell(s) should lower toward the ground along the line of your supporting leg. Range of Motion: Continue lowering your torso until it is nearly parallel to the floor, or you feel an intense stretch in your supporting hamstring, ensuring your back remains neutral throughout the movement. Return to Start: Pause at the bottom, then contract your glutes and hamstrings to slowly raise your torso back to the starting position. Your non-supporting leg should return in line with the supporting one. Switch Sides: After completing your desired number of repetitions on one side, switch your weight and repeat the movement on the other leg.', false, 'wger', 'a630de17-9170-434c-b486-96a6b8705506', 'Tierrasverdes', ''),
  ('machine-hip-abduction', 'Machine Hip Abduction', 'legs', null, 'https://wger.de/media/exercise-images/1748/923a3ff7-c269-49bd-9f03-697151a40f06.jpg', 'Technique and Execution Starting Position Seated Positioning: Sit in the machine with back against the pad Leg Placement: Inner thighs against the machine''s padded resistance points Adjust Machine: Set seat position to align your hip joint with the machine''s pivot point Movement Technique Start with legs together or slightly pressed against the inner pads Slowly push legs outward, spreading them apart Move until maximum comfortable lateral range is reached Pause briefly at the outer point of the movement Slowly return to the starting position with controlled movement Biomechanical Breakdown Muscle Engagement Primary Activation: Gluteus Medius (side hip muscle) Stabilization: Engages core and lower back muscles Functional Movement: Mimics lateral leg movement used in walking, sports, and daily activities Benefits Strength and Stability Improves Hip Stability Reduces Risk of Knee Injuries Enhances Lateral Movement Capabilities Targets Often-Neglected Muscle Groups', false, 'wger', 'b5726562-82ed-451a-89d8-8c8b13c5019a', '', ''),
  ('ankle-dorsiflexion-rocks', 'ankle dorsiflexion rocks', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1804/691c69b8-c3db-4177-8435-dd3a97d88542.webp', 'Move your knee forward, keeping your heel on the ground. Hold the position for a couple of seconds and return to the starting position.', false, 'wger', 'fa5252d3-973c-4b35-9324-a02460545283', 'Davidgj32', ''),
  ('barbell-step-back-lunge', 'Barbell Step Back Lunge', 'legs', 'Barbell', 'https://wger.de/media/exercise-images/1830/3b6c547c-ab3d-4472-93cf-561710279eab.jpg', 'Step 1: Stand with your feet hip-width apart, holding a barbell on your upper back. Step 2: Keep your back straight, chest up, and core engaged. Step 3: Take a step back with one leg and lower your body by bending both knees. Ensure that your back knee nearly touches the ground. Step 4: Push off your back foot to return to the starting position. Step 5: Repeat the movement with the other leg. Continue alternating between legs for the desired repetitions.', false, 'wger', '928eeae3-d849-4605-a470-048ca259a8c5', 'hans', ''),
  ('hammerstrength-decline-chest-press', 'Hammerstrength Decline Chest Press', 'chest', null, 'https://wger.de/media/exercise-images/1831/2d9d509f-707b-4132-961e-91a2459ca198.jpg', 'Sit upright in a hammerstrength decline chest press machine while squeezing your shoulder blades together and placing your heels firmly on the ground underneath your knees. The back pad should be contact with your head, shoulders, and butt at all times. Grab ahold of the handles with an overhand grip just outside shoulder-width apart just below your chest. Keeping your core braced by breathing into your stomach and flexing the abdominal muscles, push through your palms to extend your elbows while keeping them at a 45 degree angle from your torso. Once your arms are fully extended, return to the starting position.', false, 'wger', '920692b2-0842-428a-b925-ba0daf6b41db', 'hans', ''),
  ('external-rotation-stretch', 'External Rotation Stretch', 'shoulders', 'Barbell', 'https://wger.de/media/exercise-images/1835/ca4a0b7e-9fdd-4173-843a-f0392824abe1.jpg', 'Sit with your feet pressed against each other, and one knee raised all the way out to the side of your body. Place your elbow on your raised knee, bend it at 90 degrees, and point your hand directly forward, holding your barbell/dumbbell. Keep your shoulder depressed and retracted, raise your hand until your forearm is vertical, as if you were about to wave at someone like a robot. Lower your hand to the original position and repeat.', false, 'wger', 'a4413bcc-dcd1-4332-a09a-fee94a265e22', 'Nick E', ''),
  ('calves-foam-roller', 'Calves foam roller', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1854/ccd3c18e-c864-426f-8176-15dce14305e3.webp', 'Move your calves slowly over the foam roller', false, 'wger', '05b36227-a331-45b8-b1d5-5c7293c2df17', 'Davidgj32', ''),
  ('hamstring-foam-roller', 'Hamstring Foam roller', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1855/a6597ed8-1613-4458-ba56-4b63bc946a35.webp', 'Move your hamstrings slowly over the foam roller', false, 'wger', 'fae5378b-db4b-4ab5-9207-07a6abab917f', 'Davidgj32', ''),
  ('foam-roller-anterior-tibialis', 'Foam Roller Anterior tibialis', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1856/19c31c63-4968-4887-b8e6-4127be27fdde.jpg', 'Use the foam roller slowly in the tibial anterioris. This is english, please', false, 'wger', '8a9fff1e-0908-4706-8baa-7f400e2dac19', 'Davidgj32', ''),
  ('foam-roller-iliotibial-band', 'Foam Roller Iliotibial band', 'legs', 'none (bodyweight exercise)', 'https://wger.de/media/exercise-images/1857/92291128-cc7e-4f70-9663-80840c516fc9.jpg', 'Slide on the Foam Roller over your iliotibial band. Is english terrible checker', false, 'wger', '4d96e62c-e4ac-45be-9428-b97f18ca26d9', 'Davidgj32', ''),
